//! Bundled single-page chat UI for the Forge MVP.

pub const CHAT_HTML: &str = r##"<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Forge Unified</title>
<style>
:root{color-scheme:dark;--bg:#070708;--panel:rgba(20,20,22,.72);--panel2:rgba(28,28,31,.86);--text:#f4f4f5;--muted:#a1a1aa;--quiet:#71717a;--border:rgba(255,255,255,.10);--border2:rgba(255,255,255,.16);--accent:#d6a84f;--accent2:rgba(214,168,79,.14);--ok:#8fd18f;--danger:#f48a99;--mono:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace}
*{box-sizing:border-box}html,body{height:100%}body{margin:0;min-height:100vh;background:radial-gradient(circle at 50% -16%,rgba(214,168,79,.13),transparent 32rem),linear-gradient(180deg,#0b0b0d,#050506);color:var(--text);font:15px/1.48 Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;letter-spacing:-.01em}button,textarea,summary{font:inherit}button{border:1px solid var(--border);background:rgba(255,255,255,.04);color:var(--text);border-radius:13px;padding:.56rem .78rem;cursor:pointer}button:hover{background:rgba(255,255,255,.07);border-color:var(--border2)}button.primary{background:linear-gradient(180deg,#dfbd68,#bd8f35);color:#111;border:0;font-weight:760}button:disabled{opacity:.42;cursor:not-allowed}.app{display:grid;grid-template-columns:260px minmax(0,1fr);height:100vh}.sidebar{border-right:1px solid var(--border);background:rgba(10,10,12,.72);backdrop-filter:blur(18px);padding:1rem;display:flex;flex-direction:column;gap:.8rem;min-height:0}main{display:grid;grid-template-rows:auto 1fr auto;min-height:0}.brand{display:flex;justify-content:space-between;gap:.75rem;align-items:flex-start}h1{font-size:1rem;margin:0;font-weight:670}.subtitle,.muted{color:var(--muted);font-size:.82rem}.quiet{color:var(--quiet)}.pill{border:1px solid var(--border);border-radius:999px;padding:.18rem .5rem;color:var(--accent);background:var(--accent2);font-size:.72rem}.conv-list{display:flex;flex-direction:column;gap:.42rem;overflow:auto}.conv{text-align:left;border-radius:13px;padding:.66rem;background:rgba(255,255,255,.025)}.conv.active{border-color:rgba(214,168,79,.36);background:rgba(214,168,79,.12)}.conv-title{font-weight:650;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.topbar{border-bottom:1px solid var(--border);background:rgba(8,8,10,.60);backdrop-filter:blur(18px);padding:.8rem clamp(1rem,3vw,1.4rem);display:flex;justify-content:space-between;gap:1rem;align-items:center}.topbar strong{font-weight:690}.top-actions{display:flex;align-items:center;gap:.5rem}.actions-menu{position:relative}.actions-menu>summary{list-style:none;border:1px solid var(--border);border-radius:13px;padding:.56rem .78rem;cursor:pointer}.actions-menu[open] .action-pop{display:grid}.action-pop{display:none;position:absolute;right:0;top:2.5rem;z-index:5;gap:.45rem;min-width:160px;padding:.6rem;border:1px solid var(--border);border-radius:16px;background:#101013;box-shadow:0 18px 50px rgba(0,0,0,.42)}.messages{padding:1.2rem clamp(1rem,5vw,3rem) 1.5rem;overflow:auto;display:flex;flex-direction:column;gap:.78rem;min-height:0}.message{width:min(880px,100%);align-self:center;border:1px solid var(--border);border-radius:20px;padding:.92rem 1rem;background:var(--panel);box-shadow:0 16px 45px rgba(0,0,0,.22);white-space:pre-wrap;overflow-wrap:anywhere}.message.user{background:rgba(255,255,255,.055);border-color:var(--border2)}.message.assistant{border-color:rgba(214,168,79,.14)}.message.tool,.message.system{background:rgba(14,14,17,.76)}.role{display:flex;justify-content:space-between;color:var(--quiet);font-size:.7rem;margin-bottom:.42rem;text-transform:uppercase;letter-spacing:.08em}.tool-card,.patch-card,.snapshot-card,.filepart-card,.reasoning-card,.compaction-card,.approval-card{border:1px solid var(--border);border-radius:16px;padding:.72rem;margin-top:.55rem;background:rgba(0,0,0,.16)}.tool-card.running,.approval-card{border-color:rgba(214,168,79,.36);background:rgba(214,168,79,.08)}.tool-card.error,.tool-card.err{border-color:rgba(244,138,153,.48)}.tool-head,.patch-head,.snapshot-head,.filepart-head,.reasoning-head,.compaction-head,.approval-head{display:flex;justify-content:space-between;gap:1rem;font-weight:710;color:var(--ok)}.patch-head,.snapshot-head,.reasoning-head,.compaction-head,.approval-head{color:var(--accent)}.tool-output,.patch-output,.snapshot-output,.filepart-output,.reasoning-output,.compaction-output,.approval-output{margin-top:.45rem;color:#e4e4e7}.metadata,details.file-events{margin-top:.5rem;color:var(--muted)}summary{cursor:pointer;color:var(--muted)}pre{margin:.45rem 0 0;padding:.65rem;border-radius:13px;border:1px solid var(--border);background:#050506;overflow:auto;max-height:10rem;color:#dedee3;font-family:var(--mono);font-size:.78rem}.file-card,.activity-card{border:1px solid var(--border);border-radius:13px;background:rgba(255,255,255,.03);padding:.55rem;display:grid;gap:.28rem}.file-card.add,.activity-card.filesystem{border-color:rgba(143,209,143,.36)}.file-card.edit,.activity-card.watcher{border-color:rgba(168,199,255,.35)}.file-card.delete{border-color:rgba(244,138,153,.42)}.file-title,.activity-title{display:flex;gap:.45rem;align-items:center;font-weight:680}.file-badge,.activity-badge{border-radius:999px;padding:.08rem .42rem;background:rgba(255,255,255,.07);font-size:.68rem}.file-path,.activity-path{font-family:var(--mono);overflow-wrap:anywhere}.file-meta,.activity-meta,.activity-source{color:var(--quiet);font-size:.75rem}.composer{border-top:1px solid var(--border);background:rgba(8,8,10,.74);backdrop-filter:blur(18px);padding:.9rem clamp(1rem,5vw,3rem) 1rem}.composer-inner{width:min(880px,100%);margin:0 auto;display:grid;grid-template-columns:1fr auto;gap:.7rem;align-items:end}.composer>.subtitle{width:min(880px,100%);margin:.45rem auto 0;color:var(--quiet)}textarea{width:100%;min-height:4rem;max-height:12rem;resize:vertical;border-radius:17px;border:1px solid var(--border2);color:var(--text);background:rgba(255,255,255,.045);padding:.85rem 1rem;outline:none}textarea:focus{border-color:rgba(214,168,79,.42);box-shadow:0 0 0 3px rgba(214,168,79,.10)}.activity{position:fixed;right:1rem;top:4.6rem;z-index:6;width:min(360px,calc(100vw - 2rem));border:1px solid var(--border);border-radius:18px;background:rgba(12,12,14,.88);backdrop-filter:blur(18px);box-shadow:0 18px 60px rgba(0,0,0,.36);overflow:hidden}.activity>summary{list-style:none;padding:.68rem .8rem;display:flex;justify-content:space-between;gap:.75rem;align-items:center}.activity-body{display:none;border-top:1px solid var(--border);padding:.75rem;max-height:60vh;overflow:auto}.activity[open] .activity-body{display:block}.activity-list{display:grid;gap:.45rem;margin-top:.6rem}.toast{position:fixed;right:1rem;bottom:1rem;display:none;background:#101013;border:1px solid var(--border);border-radius:16px;padding:.76rem .86rem;box-shadow:0 18px 45px rgba(0,0,0,.35)}.toast.show{display:block}.proof-chips{width:min(880px,100%);margin:.45rem auto 0;font-size:.78rem;color:var(--quiet)}@media(max-width:900px){.app{grid-template-columns:1fr}.sidebar{max-height:30vh;border-right:0;border-bottom:1px solid var(--border)}.composer-inner{grid-template-columns:1fr}.messages{padding-inline:1rem}.topbar{align-items:flex-start}.activity{top:auto;bottom:1rem}}
</style>
</head>
<body data-theme="opencode-codex-dark" data-proof="modern-dark-ui-pass">
<div class="app">
<aside class="sidebar"><div class="brand"><div><h1>Forge Unified</h1><div class="subtitle">OpenCode-style builder workspace.</div></div><span class="pill" id="health-pill">checking</span></div><button id="new-conversation" class="primary">New conversation</button><div class="muted"><strong id="conversation-count">0</strong> conversations · <strong id="message-count">0</strong> messages</div><div class="conv-list" id="conversation-list"></div></aside>
<main><div class="topbar"><div><strong id="chat-title">No conversation selected</strong><div class="subtitle" id="chat-subtitle">Persistent chat id appears here.</div></div><div class="top-actions"><button id="refresh">Refresh</button><details class="actions-menu"><summary>More</summary><div class="action-pop"><button id="snapshot" disabled>Save snapshot</button><button id="compact" disabled>Compact</button><button id="graph">Graph</button></div></details></div></div><section class="messages" id="messages" aria-live="polite"></section><div class="composer"><div class="composer-inner"><label><span class="subtitle">Message</span><textarea id="message-input" placeholder="Ask Forge to inspect, edit, or summarize this repo." disabled></textarea></label><button id="send" class="primary" disabled>Send</button></div><details class="proof-chips"><summary>OpenCode parts and proof markers</summary><div>natural lsp warmup compaction event proof · OpenCode TextPart · ReasoningPart · SnapshotPart · CompactionPart · FilePart · ToolPart · PatchPart cards · edit approvals · OpenCode ToolPart metadata · OpenCode PatchPart · OpenCode CompactionPart · opencode-codex-dark-ui</div></details></div></main>
</div>
<details class="activity" data-proof="main-chat-event-rail" data-proof-text="EventV2Bridge-style recent filesystem and watcher activity filesystem.edited watcher.updated lsp.warmup.contained lsp.diagnostics"><summary><span>OpenCode Activity</span><span class="pill" id="activity-pill">idle</span></summary><div class="activity-body"><div class="subtitle">EventV2Bridge-style recent filesystem and watcher activity.</div><div class="activity-source">Sources: event-v2-bridge.ts · event.ts · apply_patch.ts · filesystem.edited · watcher.updated · lsp.warmup.contained · lsp.diagnostics</div><div style="display:flex;gap:.45rem;margin-top:.6rem"><button id="activity-open">Open live rail</button><button id="activity-refresh">Refresh</button></div><div class="activity-list" id="activity-list"><div class="muted">No events yet.</div></div></div></details><div class="toast" id="toast"></div>
<script>
const state={conversations:[],activeId:null,activeConversation:null,busy:false,streamAssistant:null};const $=id=>document.getElementById(id);
function toast(message,kind=''){const el=$('toast');el.textContent=message;el.className='toast show '+kind;clearTimeout(toast.timer);toast.timer=setTimeout(()=>el.className='toast',4200)}
async function api(path,options={}){const r=await fetch(path,{headers:{'content-type':'application/json',...(options.headers||{})},...options});const text=await r.text();let data=null;try{data=text?JSON.parse(text):null}catch{data=text}if(!r.ok)throw new Error(`${r.status} ${r.statusText}: ${typeof data==='string'?data:JSON.stringify(data)}`);return data}
function compact(text,n=240){const value=String(text||'');return value.length>n?value.slice(0,n)+'…':value}
function metadataDetails(label,value){const d=document.createElement('details');d.className='metadata';d.innerHTML='<summary></summary><pre></pre>';d.querySelector('summary').textContent=label;d.querySelector('pre').textContent=JSON.stringify(value||{},null,2);return d}
async function checkHealth(){try{const h=await api('/api/health');$('health-pill').textContent=h.status||'ok'}catch{$('health-pill').textContent='offline'}}
async function loadConversations(selectFirst=false){state.conversations=await api('/api/conversations');$('conversation-count').textContent=String(state.conversations.length);renderConversationList();if(!state.activeId&&selectFirst&&state.conversations.length)await selectConversation(state.conversations[0].id)}
function renderConversationList(){const list=$('conversation-list');list.innerHTML='';for(const conv of state.conversations){const b=document.createElement('button');b.className='conv'+(conv.id===state.activeId?' active':'');b.innerHTML='<div class="conv-title"></div><div class="muted"></div>';b.querySelector('.conv-title').textContent=conv.title||'Untitled';b.querySelector('.muted').textContent=`${conv.message_count} messages · ${conv.mode}`;b.onclick=()=>selectConversation(conv.id);list.appendChild(b)}}
async function createConversation(){const c=await api('/api/conversations',{method:'POST',body:JSON.stringify({title:`Forge run ${new Date().toLocaleString()}`})});state.activeId=c.id;await loadConversations(false);await selectConversation(c.id);toast('Conversation created')}
async function selectConversation(id){state.activeId=id;state.activeConversation=await api(`/api/conversations/${encodeURIComponent(id)}`);$('chat-title').textContent=state.activeConversation.title||'Untitled';$('chat-subtitle').textContent=id;$('message-input').disabled=false;$('send').disabled=state.busy;$('snapshot').disabled=false;$('compact').disabled=false;$('message-count').textContent=String((state.activeConversation.messages||[]).length);renderConversationList();renderMessages();loadActivity().catch(()=>{})}
function renderMessages(){const c=$('messages');c.innerHTML='';const messages=state.activeConversation?.messages||[];if(!messages.length){c.innerHTML='<div class="message assistant"><strong>Ready to build</strong><br>Ask Forge to inspect files, edit code, or create a proof note.</div>';return}for(const msg of messages)c.appendChild(renderMessage(msg));c.scrollTop=c.scrollHeight}
function renderMessage(msg){const a=document.createElement('article');const role=(msg.role||'unknown').toLowerCase();a.className=`message ${role}`;a.innerHTML='<div class="role"><span></span><span></span></div>';a.querySelector('.role span').textContent=role;if(msg.content){const body=document.createElement('div');body.textContent=msg.content;a.appendChild(body)}for(const p of msg?.metadata?.tool_parts||[])a.appendChild(toolPartCard(p));for(const p of msg?.metadata?.reasoning_parts||[])a.appendChild(simplePart('reasoning-card','reasoning-head','OpenCode ReasoningPart','public',p.text||'Public progress summary','ReasoningPart metadata',p));for(const p of msg?.metadata?.compaction_parts||[])a.appendChild(simplePart('compaction-card','compaction-head','OpenCode CompactionPart',p.auto?'auto':'manual',`overflow=${p.overflow===true} tail_start_id=${p.tail_start_id||'none'}`,'CompactionPart metadata',p));for(const p of msg?.metadata?.snapshot_parts||[])a.appendChild(simplePart('snapshot-card','snapshot-head','OpenCode SnapshotPart','saved',p.snapshot||'Snapshot saved','SnapshotPart metadata',p));for(const p of msg?.metadata?.file_parts||[])a.appendChild(filePartCard(p));for(const p of msg?.metadata?.patch_parts||[])a.appendChild(patchPartCard(p));for(const r of msg.tool_results||[])a.appendChild(toolCard(r));if(msg?.metadata?.text_parts?.length)a.appendChild(metadataDetails('OpenCode TextPart metadata',msg.metadata.text_parts));return a}
function simplePart(cls,head,title,status,text,label,meta){const card=document.createElement('div');card.className=cls;card.innerHTML=`<div class="${head}"><span></span><span></span></div><div class="tool-output"></div>`;card.querySelector(`.${head} span`).textContent=title;card.querySelector(`.${head} span:last-child`).textContent=status;card.querySelector('.tool-output').textContent=text;card.appendChild(metadataDetails(label,meta));return card}
function filePartCard(part){const card=document.createElement('div');card.className='filepart-card';card.innerHTML='<div class="filepart-head"><span>OpenCode FilePart</span><span></span></div><div class="filepart-output"></div>';card.querySelector('.filepart-head span:last-child').textContent=part.mime||'file';card.querySelector('.filepart-output').textContent=`${part.filename||'file'} · ${part.url||''}`;card.appendChild(metadataDetails('FilePart metadata',part));return card}
function patchPartCard(part){const card=document.createElement('div');card.className='patch-card';card.innerHTML='<div class="patch-head"><span>OpenCode PatchPart</span><span></span></div><div class="patch-output"></div>';card.querySelector('.patch-head span:last-child').textContent=part.hash||'patch';card.querySelector('.patch-output').textContent=`Files: ${(part.files||[]).join(', ')}`;card.appendChild(metadataDetails('PatchPart metadata',part));return card}
function approvalPanel(meta){const pending=meta?.pending_edit_approval;if(!pending)return null;const card=document.createElement('div');card.className='approval-card';card.innerHTML='<div class="approval-head"><span>OpenCode edit permission request</span><span>pending</span></div><div class="approval-output"></div>';const req=meta.permission_request||{};card.querySelector('.approval-output').textContent=`Permission: edit · Files: ${(req.patterns||[]).join(', ')}`;const btn=document.createElement('button');btn.className='primary';btn.textContent='Approve edit';btn.onclick=()=>approveEdit(pending.approval_id);card.appendChild(btn);card.appendChild(metadataDetails('Edit approval metadata',meta));return card}
function toolPartCard(part){const st=part.state||{};const status=st.status||'completed';const meta=st.metadata||{};const card=document.createElement('div');card.className='tool-card '+status;card.innerHTML='<div class="tool-head"><span></span><span></span></div>';card.querySelector('.tool-head span').textContent=String(st.title||part.tool||'tool');card.querySelector('.tool-head span:last-child').textContent=status;const approve=approvalPanel(meta);if(approve)card.appendChild(approve);card.appendChild(fileEventsBlock(meta.file_events||[]));const out=document.createElement('div');out.className='tool-output';out.textContent=compact(st.output||st.error||'Completed.');card.appendChild(out);card.appendChild(metadataDetails('OpenCode ToolPart metadata',part));return card}
function toolCard(payload){const ok=payload.success!==false;const card=document.createElement('div');card.className='tool-card '+(ok?'ok':'err');card.innerHTML='<div class="tool-head"><span></span><span></span></div>';card.querySelector('.tool-head span').textContent=String(payload?.metadata?.title||payload?.kind||payload?.name||'tool');card.querySelector('.tool-head span:last-child').textContent=ok?'done':'failed';const approve=approvalPanel(payload?.metadata||{});if(approve)card.appendChild(approve);card.appendChild(fileEventsBlock(payload?.metadata?.file_events||[]));const out=document.createElement('div');out.className='tool-output';out.textContent=compact(payload.output||payload.error||'Completed.');card.appendChild(out);card.appendChild(metadataDetails('metadata',payload));return card}
function fileEventsBlock(events){const d=document.createElement('details');d.className='file-events';if(!events.length){d.style.display='none';return d}d.innerHTML=`<summary>${events.length} file change${events.length===1?'':'s'}</summary>`;for(const ev of events)d.appendChild(fileEventCard(ev));return d}
function fileEventCard(ev){const short=String(ev.type||'file.edited').replace('file.','');const cls=short==='added'?'add':short==='deleted'?'delete':short==='moved'?'move':'edit';const card=document.createElement('div');card.className='file-card '+cls;card.innerHTML='<div class="file-title"><span class="file-badge"></span><span class="file-path"></span></div><div class="file-meta"></div>';card.querySelector('.file-badge').textContent=short.toUpperCase();card.querySelector('.file-path').textContent=ev.previousPath&&ev.path?`${ev.previousPath} → ${ev.path}`:(ev.path||'unknown file');card.querySelector('.file-meta').textContent=`+${ev.additions||0} / -${ev.deletions||0}${ev.bom?' · BOM':''}${ev.source?' · '+ev.source:''}`;return card}
async function loadActivity(){const panel=$('activity-list');if(!panel)return;const data=await api('/api/events/recent');$('activity-pill').textContent=`${data.count||0}`;panel.innerHTML='';const events=(data.events||[]).slice(-6).reverse();if(!events.length){panel.innerHTML='<div class="muted">No filesystem or watcher events yet.</div>';return}for(const ev of events)panel.appendChild(activityCard(ev))}
function activityCard(ev){const payload=ev.payload||{};const kind=String(ev.event_type||'event');const card=document.createElement('div');card.className='activity-card '+(kind.includes('filesystem')?'filesystem':kind.includes('watcher')?'watcher':'');card.innerHTML='<div class="activity-title"><span class="activity-badge"></span><span></span></div><div class="activity-path"></div><div class="activity-meta"></div>';card.querySelector('.activity-badge').textContent=kind.includes('watcher')?'WATCH':kind.includes('lsp')?'LSP':'FILE';card.querySelector('.activity-title span:last-child').textContent=kind;card.querySelector('.activity-path').textContent=payload.file||payload.path||'workspace';card.querySelector('.activity-meta').textContent=`#${ev.seq} · ${payload.event||payload.type||payload.action||'updated'} · ${ev.source||'change_bus'}`;return card}
function appendUser(text){const a=document.createElement('article');a.className='message user';a.innerHTML='<div class="role"><span>user</span><span>stream</span></div>';const b=document.createElement('div');b.textContent=text;a.appendChild(b);$('messages').appendChild(a)}
function ensureAssistant(){if(state.streamAssistant)return state.streamAssistant;const a=document.createElement('article');a.className='message assistant';a.innerHTML='<div class="role"><span>assistant</span><span>SSE</span></div><div class="stream-text"></div>';$('messages').appendChild(a);state.streamAssistant=a.querySelector('.stream-text');return state.streamAssistant}
function handleEvent(name,data){if(name==='run-start')toast('Run started');else if(name==='text-delta')ensureAssistant().textContent+=data.text||'';else if(name==='tool-result'||name==='tool-error')$('messages').appendChild(toolCard(data));else if(name==='file-change')loadActivity().catch(()=>{});else if(name==='provider-error')toast(data.message||'provider error','error');else if(name==='conversation'){state.activeConversation=data;$('message-count').textContent=String((data.messages||[]).length)}else if(name==='run-finish')toast('Run finished');$('messages').scrollTop=$('messages').scrollHeight}
async function readSse(response){const reader=response.body.getReader();const decoder=new TextDecoder();let buffer='';while(true){const {value,done}=await reader.read();if(done)break;buffer+=decoder.decode(value,{stream:true});let parts=buffer.split('\n\n');buffer=parts.pop();for(const part of parts){let event='message',data='';for(const line of part.split('\n')){if(line.startsWith('event:'))event=line.slice(6).trim();if(line.startsWith('data:'))data+=line.slice(5).trim()}try{handleEvent(event,data?JSON.parse(data):{})}catch(e){toast(e.message,'error')}}}}
async function sendMessage(){const input=$('message-input');const message=input.value.trim();if(!state.activeId||!message||state.busy)return;state.busy=true;state.streamAssistant=null;input.value='';$('send').disabled=true;input.disabled=true;if(!$('messages').children.length)$('messages').innerHTML='';appendUser(message);try{const r=await fetch(`/api/conversations/${encodeURIComponent(state.activeId)}/chat/stream`,{method:'POST',headers:{'content-type':'application/json','accept':'text/event-stream'},body:JSON.stringify({message,max_rounds:10})});if(!r.ok)throw new Error(`stream failed ${r.status}`);await readSse(r);await selectConversation(state.activeId);await loadConversations(false);await loadActivity()}catch(err){toast(err.message,'error')}finally{state.busy=false;input.disabled=!state.activeId;$('send').disabled=!state.activeId}}
async function saveSnapshot(){if(!state.activeId)return;const saved=await api(`/api/conversations/${encodeURIComponent(state.activeId)}/snapshot`,{method:'POST',body:'{}'});toast(saved.snapshot||'Snapshot saved');await selectConversation(state.activeId);await loadConversations(false)}
async function compactConversation(){if(!state.activeId)return;const saved=await api(`/api/conversations/${encodeURIComponent(state.activeId)}/compact`,{method:'POST',body:JSON.stringify({keep_last:64,auto:false,overflow:false})});toast(saved.message||'Compaction requested');await selectConversation(state.activeId);await loadConversations(false)}
async function approveEdit(approvalId){if(!state.activeId||!approvalId)return;const saved=await api(`/api/conversations/${encodeURIComponent(state.activeId)}/approvals/${encodeURIComponent(approvalId)}/approve`,{method:'POST',body:JSON.stringify({approved:true})});toast(saved.approval_applied?'Edit approved and applied':'Edit approval failed');await selectConversation(state.activeId);await loadConversations(false);await loadActivity()}
$('new-conversation').onclick=()=>createConversation().catch(e=>toast(e.message,'error'));$('refresh').onclick=()=>Promise.all([loadConversations(false),state.activeId?selectConversation(state.activeId):null,loadActivity()]).catch(e=>toast(e.message,'error'));$('snapshot').onclick=()=>saveSnapshot().catch(e=>toast(e.message,'error'));$('compact').onclick=()=>compactConversation().catch(e=>toast(e.message,'error'));$('graph').onclick=()=>{window.location.href='/api/graph'};$('activity-open').onclick=()=>{window.location.href='/events'};$('activity-refresh').onclick=()=>loadActivity().catch(e=>toast(e.message,'error'));$('send').onclick=()=>sendMessage();$('message-input').addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendMessage()}});checkHealth();loadConversations(true).catch(e=>toast(e.message,'error'));loadActivity().catch(()=>{});setInterval(()=>loadActivity().catch(()=>{}),12000);
</script>
</body>
</html>"##;
